// ============================================================
// PARSE + SMART CONTEXT DETECTION — v2 FIXED
// FIX: intent detection lebih cerdas — tidak trigger needsTicket
//      hanya karena kata "ticket" ada di kalimat umum.
//      Category "general" sekarang benar-benar general → AI pakai
//      pengetahuan sendiri, tidak dibatasi hanya context DB.
// ============================================================
const body = $input.item.json.body || {};
const rawQuestion = body.question || '';
const question = rawQuestion.toLowerCase();

// Detect ticket ID — #angka eksplisit
const ticketIdMatch = question.match(/#(\d+)/);
const detectedTicketId = ticketIdMatch ? parseInt(ticketIdMatch[1]) : (body.ticketId || body.ticket_id || null);

// Extract keywords
const stopwords = ['yang','untuk','dari','dengan','adalah','pada','ke','di','dan','atau','jika','maka','tetapi','saya','kamu','apa','kenapa','bagaimana','kapan','siapa','tolong','bisa','tidak','ada','ini','itu','juga','sudah','belum','masih','lagi','saja','agar','supaya','setelah','sebelum','ketika','karena','sebab','oleh','namun','akan','harus','perlu','coba','mohon','info','tahu','minta','bantu','berikan','tampilkan','tunjukkan','jelaskan','buatkan','cari','coba','saran','berikan','ticket','tiket'];
const keywords = rawQuestion.split(/\s+/).filter(w => w.length > 3 && !stopwords.includes(w.toLowerCase())).slice(0, 10);

// ── Intent detection ──────────────────────────────────────────
// FIX: needsTicket HANYA jika:
//   1. Ada ticket ID eksplisit (#angka), ATAU
//   2. Pertanyaan spesifik tentang data ticket (summary, root cause, status, dll)
//   BUKAN hanya karena kata "ticket" muncul di kalimat umum

let category = 'general';
let needsTicket = false;
let needsKB = false;
let needsSimilar = false;

// Ticket-specific: HARUS ada ticket ID atau kata kunci data spesifik
const isTicketDataQuery = (
  question.includes('summary') ||
  question.includes('root cause') ||
  question.includes('ringkasan') ||
  question.includes('penyebab') ||
  question.includes('akar masalah') ||
  question.includes('handling') ||
  question.includes('penanganan') ||
  question.includes('tindak lanjut') ||
  question.includes('action taken') ||
  question.includes('timeline')
);

if (detectedTicketId) {
  // Ada #ID → selalu fetch ticket
  needsTicket = true;
  category = 'ticket_specific';
} else if (isTicketDataQuery) {
  // Tanya tentang data ticket tapi tanpa ID — mungkin konteks percakapan
  needsTicket = false; // tidak bisa fetch tanpa ID
  category = 'ticket_specific';
}
// FIX: "ticket" saja tanpa ID dan tanpa query data spesifik → general
// User mungkin tanya "cara buat ticket" atau "apa itu ticket system" → tidak perlu DB

// Troubleshooting & KB
if (
  question.includes('error') || question.includes('masalah') ||
  question.includes('rusak') || question.includes('gagal') ||
  question.includes('cara') || question.includes('tidak bisa') ||
  question.includes('solusi') || question.includes('langkah') ||
  question.includes('troubleshoot') || question.includes('runbook') ||
  question.includes('perbaiki') || question.includes('kenapa') ||
  question.includes('mengapa')
) {
  needsKB = true;
  needsSimilar = true;
  if (category === 'general') category = 'troubleshooting';
}

// Historical search
if (
  question.includes('mirip') || question.includes('serupa') ||
  question.includes('pernah') || question.includes('historical') ||
  question.includes('sebelumnya') || question.includes('kasus lain')
) {
  needsSimilar = true;
  if (category === 'general') category = 'historical';
}

// Incident report
if (
  question.includes('incident report') ||
  question.includes('laporan insiden') ||
  question.includes('buatkan laporan')
) {
  needsTicket = true;
  category = 'incident_report';
}

// Explanation / konsep umum IT
if (
  question.includes('apa itu') || question.includes('jelaskan') ||
  question.includes('perbedaan') || question.includes('pengertian') ||
  question.includes('definisi') || question.includes('explain')
) {
  needsKB = true;
  if (category === 'general') category = 'explanation';
}

// Auto create
if (
  question.includes('buat ticket') || question.includes('buat tiket') ||
  question.includes('laporkan masalah')
) {
  if (category === 'general') category = 'auto_create';
}

// Recommendation
if (
  question.includes('rekomendasi') || question.includes('saran') ||
  question.includes('tools') || question.includes('sebaiknya')
) {
  needsKB = true;
  needsSimilar = true;
  if (category === 'general') category = 'recommendation';
}

return {
  json: {
    userId: body.userId || body.user_id || 'unknown',
    userName: body.userName || body.user_name || 'unknown',
    question: rawQuestion,
    conversationHistory: Array.isArray(body.conversationHistory) ? body.conversationHistory : [],
    detectedTicketId,
    keywords,
    category,
    needsTicket,
    needsKB,
    needsSimilar,
    timestamp: new Date().toISOString()
  }
};

// ============================================================
// BUILD AI CONTEXT — Merge all fetched data
// FIX: defensive null/undefined guards agar tidak crash
// jika ctx.keywords undefined, ticket fields null, dll.
// ============================================================
const ctx = $('Parse & Detect Intent').item.json;
const fetched = $input.item.json;

const ticket = fetched.ticket || null;
const runbooks = fetched.runbooks || [];
const similarTickets = fetched.similarTickets || [];

// FIX: keywords bisa undefined jika Parse node gagal / berubah struktur
const keywords = Array.isArray(ctx.keywords) ? ctx.keywords : [];

let contextText = `USER QUESTION: ${ctx.question || ''}
`;
contextText += `CATEGORY: ${ctx.category || 'general'}
`;
contextText += `KEYWORDS: ${keywords.join(', ') || '(none)'}

`;

// Ticket section
if (ticket) {
  contextText += `═══ TICKET #${ticket.id} ═══
`;
  if (ticket.title) contextText += `Title: ${ticket.title}
`;
  contextText += `Type: ${ticket.type} | Status: ${ticket.status}
`;

  // FIX: semua field bisa null — gunakan string fallback sebelum substring
  const summaryText = ticket.summaryTicket || ticket.summary_ticket || null;
  const rootCauseText = ticket.rootCause || ticket.root_cause || null;
  const timelineAction = ticket.timelineActionTaken || ticket.timeline_action_taken || null;
  const timelineTindak = ticket.timelineTindakLanjut || ticket.timeline_tindak_lanjut || null;

  if (summaryText) contextText += `
📋 SUMMARY (tampilkan langsung ke user):
${String(summaryText).substring(0, 800)}
`;
  else contextText += `
📋 SUMMARY: Belum tersedia (ticket belum DONE/RESOLVED)
`;

  if (rootCauseText) contextText += `
🔍 ROOT CAUSE:
${String(rootCauseText).substring(0, 500)}
`;
  else contextText += `
🔍 ROOT CAUSE: Belum tersedia
`;

  if (timelineAction) contextText += `
📅 ACTION TAKEN:
${String(timelineAction).substring(0, 500)}
`;
  if (timelineTindak) contextText += `
📅 TINDAK LANJUT:
${String(timelineTindak).substring(0, 500)}
`;

  contextText += `
`;
}

// Knowledge Base section
if (runbooks.length > 0) {
  contextText += `═══ KNOWLEDGE BASE / RUNBOOK ═══
`;
  runbooks.forEach((kb, i) => {
    contextText += `
${i+1}. [${kb.category || 'KB'}] ${kb.title || ''}
`;
    contextText += `${String(kb.content || '').substring(0, 400)}
`;
    if (kb.success_rate) contextText += `Success Rate: ${kb.success_rate}%
`;
  });
  contextText += `
`;
} else if (ctx.needsKB) {
  contextText += `═══ KNOWLEDGE BASE ═══
Tidak ada runbook relevan ditemukan.

`;
}

// Similar Tickets section
if (similarTickets.length > 0) {
  contextText += `═══ HISTORICAL TICKETS SERUPA ═══
`;
  contextText += `(Hanya tampilkan ticket dari daftar ini. JANGAN mengarang ticket ID.)

`;
  similarTickets.forEach((t, i) => {
    contextText += `${i+1}. Ticket #${t.ticketId} — ${t.issue || 'N/A'}
`;
    if (t.summary) contextText += `   Summary: ${String(t.summary).substring(0, 200)}
`;
    if (t.rootCause) contextText += `   Root Cause: ${String(t.rootCause).substring(0, 150)}
`;
  });
  contextText += `
`;
} else if (ctx.needsSimilar) {
  contextText += `═══ HISTORICAL TICKETS ═══
Tidak ada ticket serupa. JANGAN mengarang data.

`;
}

// Conversation history
if (ctx.conversationHistory && ctx.conversationHistory.length > 0) {
  contextText += `═══ RIWAYAT PERCAKAPAN ═══
`;
  ctx.conversationHistory.slice(-3).forEach(turn => {
    contextText += `User: ${turn.question}
AI: ${String(turn.answer || '').substring(0, 100)}...

`;
  });
}

// Special instruction for incident report
if (ctx.category === 'incident_report') {
  contextText += `═══ INSTRUKSI KHUSUS ═══
User meminta Incident Report untuk ticket #${ctx.detectedTicketId}.
Buat laporan enterprise format:
1. Executive Summary
2. Detail Insiden
3. Timeline
4. Root Cause Analysis
5. Resolusi
6. Rekomendasi
Gunakan data dari context ticket di atas.

`;
}

return {
  json: {
    ctx,
    contextText,
    hasTicket: !!ticket,
    hasKB: runbooks.length > 0,
    hasSimilar: similarTickets.length > 0
  }
};

