={
  "success": true,
  "answer": {{ JSON.stringify($('AI Agent').item.json.output || $('AI Agent').item.json.text || '') }},
  "questionCategory": "{{ $('Parse & Detect Intent').item.json.category }}",
  "context": {
    "hadTicket": {{ $('Build AI Context').item.json.hasTicket }},
    "hadKnowledge": {{ $('Build AI Context').item.json.hasKB }},
    "hadSimilar": {{ $('Build AI Context').item.json.hasSimilar }}
  },
  "processingTimeMs": {{ Date.now() - new Date($('Parse & Detect Intent').item.json.timestamp).getTime() }},
  "timestamp": "{{ new Date().toISOString() }}"
}
